xql_query:
datamodel dataset = apache_httpd_raw
// 1. Filter for 401 Unauthorized responses
| filter xdm.network.http.response_code = "401"
// --- ADDED FILTER: Ensure critical grouping fields are NOT null to prevent aggregation failure ---
| filter xdm.source.ipv4 != null and xdm.source.user.username != null
// 2. Aggregate the counts by Attacker IP, Target Username, and the URL being hit
| comp count(_time) as auth_failure_count,
values(xdm.network.http.url) as attempted_urls,
values(xdm.source.user_agent) as user_agents_used,
min(_time) as first_occurrence,
max(_time) as last_occurrence
by xdm.source.ipv4, xdm.source.user.username, xdm.network.http.url
// 3. Set the threshold for alerting
| filter auth_failure_count >= 3
// 4. Select the fields for the final alert (mandatory for SOAR)
// addrawdata=true is applied to the final result set for full context
| fields auth_failure_count, attempted_urls, user_agents_used, first_occurrence, last_occurrence,
xdm.source.ipv4, xdm.source.user.username, xdm.network.http.url
| sort desc auth_failure_count
